VALUES
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '요즘 자주 찾는 색깔은 무엇인가요?', 1, '색깔 하나로 기분이 달라질 때가 있어요.', '지금 입은 옷이나 주변 소품을 보세요.', '그 색을 보면 어떤 기분이 드나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 자주 듣는 노래는 무엇인가요?', 1, '좋은 노래는 하루를 버티는 힘이 돼요.', '플레이리스트 맨 위에 있는 곡을 보세요.', '이 노래가 왜 마음을 편하게 해줄까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '비 올 때 듣고 싶은 노래가 있나요?', 1, '빗소리에 어울리는 노래는 즐거움을 줘요.', '차분한 발라드나 연주곡을 떠올려 보세요.', '이 노래를 들으면 어떤 기분이 드나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '카페에서 항상 고르는 메뉴는 무엇인가요?', 1, '익숙한 맛은 마음을 편안하게 해요.', '커피나 티 혹은 에이드 종류를 생각해보세요.', '그 맛을 볼 때 왜 기분이 놓이나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '계절이 바뀔 때 기억나는 냄새가 있나요?', 1, '공기 속에도 계절마다 다른 향이 섞여 있어요.', '풀냄새나 찬 바람 혹은 낙엽 향을 생각해보세요.', '그 향기는 어떤 기억을 데려오나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 과일은 무엇인가요?', 1, '과일의 단맛은 행복하게 만들죠,', '사과, 포도, 딸기 등 떠오르는 걸 말해보세요.', '그 과일을 먹을 때 어떤 즐거움이 있나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '집에서 가장 좋아하는 컵은 무엇인가요?', 1, '매일 쓰는 물건에도 정이 가기 마련이에요.', '자주 쓰는 머그컵이나 유리잔을 보세요.', '그 컵을 쓸 때 왜 유독 마음이 편한가요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '요즘 자주 보는 영상의 주제는 무엇인가요?', 1, '관심사가 어디에 있는지 보여주는 신호예요.', '브이로그, 운동, 공부 등 즐겨찾기를 보세요.', '그 영상을 자주 보게 된 이유는 무엇일까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 날씨는 어떤 상태인가요?', 1, '날씨에 따라 하고 싶은 일도 달라져요.', '구름 없는 맑은 날이나 눈 오는 날인가요?', '그런 날씨에 밖을 나가면 어떤 기분인가요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '빵집에 가면 가장 먼저 집는 빵은 무엇인가요?', 1, '취향이 가장 솔직하게 드러나는 순간이에요.', '달콤한 크림빵이나 담백한 식빵을 떠올려 보세요.', '왜 그 맛에 자꾸 손이 가는 걸까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '최근 새로 시도해서 재밌던 일은 무엇인가요?', 2, '몰랐던 모습을 발견하는 건 신선한 경험이에요.', '최근에 가본 장소나 운동을 찾아보세요.', '이 일이 일상을 어떻게 생기 있게 만드나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '혼자 시간을 보낼 때 찾는 장소는 어디인가요?', 2, '가끔은 세상과 잠시 거리를 둘 곳이 필요해요.', '자주 가는 카페나 공원 벤치를 떠올려 보세요.', '그곳에 있으면 왜 나다운 느낌이 들까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가방 속에 늘 챙기는 물건은 무엇인가요?', 2, '물건 하나에도 평소 습관이 담겨 있어요.', '거울이나 메모장 혹은 이어폰을 확인해보세요.', '이 물건에 담긴 모습은 어떤 걸까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '집에서 가장 편한 자리는 어디인가요?', 2, '방 안에도 마음이 머무는 구석이 있어요.', '침대 위나 소파 한쪽을 생각해보세요.', '그 자리가 쉬는 데 어떤 도움을 주나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '주말 아침에 가장 하고 싶은 활동은 무엇인가요?', 2, '쉬는 날의 시작을 상상하면 기분이 좋아져요.', '느지막한 식사나 가벼운 산책을 그려보세요.', '이 활동이 주말을 어떻게 더 즐겁게 할까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 신발은 무엇인가요?', 2, '편안한 신발은 발걸음을 가볍게 해요.', '운동화나 구두 혹은 편한 슬리퍼인가요?', '그 신발을 신고 어디로 가고 싶은가요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '여행지에서 꼭 들르는 곳은 어디인가요?', 2, '여행을 가기도 전부터 꼭 가고 싶은 공간이 있기 마련이죠.', '조용한 사찰, 현지인 추천 맛집, 기념품 가게 혹은 미술관인가요?', '그곳에서 어떤 즐거움을 얻는지 궁금해요.'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '책을 고를 때 가장 먼저 보는 것은 무엇인가요?', 2, '이야기를 고르는 나만의 기준이 있어요.', '표지 디자인이나 제목 혹은 첫 문장인가요?', '어떤 분위기에 끌려 책을 집어 드나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 아끼는 옷은 어떤 스타일인가요?', 2, '옷은 나를 표현하는 가장 쉬운 방법이에요.', '편안한 옷이나 화려한 옷을 떠올려 보세요.', '그 옷을 입었을 때의 기분은 어떤가요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '좋아하는 향수나 섬유유연제 향이 있나요?', 2, '향기는 공간의 분위기를 바꿔주기도 해요.', '비누 향이나 꽃향기 혹은 나무 냄새인가요?', '그 향이 나를 어떻게 만들어주는 것 같나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '남들은 모르지만 혼자 발견한 풍경이 있나요?', 3, '자신만의 시선으로 세상을 보는 건 멋진 일이에요.', '길가에 핀 꽃이나 특이한 구름을 떠올려 보세요.', '그 장면에서 어떤 매력을 발견했나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '서점에서 제목만 보고 고르는 분야는 무엇인가요?', 3, '호기심이 어디로 향하는지 살펴보는 시간이에요.', '소설이나 예술 혹은 자기계발 분야를 골라보세요.', '왜 이 주제에 자꾸 마음이 이끌릴까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '무인도에 딱 하나만 가져간다면 무엇인가요?', 3, '하나만 골라야 한다면 진짜 소중한 게 보여요.', '즐거움을 주는 물건이나 책을 골라보세요.', '이 선택이 삶에서 왜 그렇게 중요할까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '입었을 때 가장 본인다운 옷차림은 무엇인가요?', 3, '만족스러운 스타일이 최고의 옷차림이에요.', '가장 즐겨 입는 상의나 아끼는 신발인가요?', '그 옷을 입었을 때 왜 자신감이 생기나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '나만 알고 있는 맛집이 있나요?', 3, '소중한 사람에게만 알려주고 싶은 곳이 있죠.', '숨겨진 식당이나 작은 카페를 떠올려 보세요.', '그곳의 어떤 점이 나를 만족하게 하나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '스트레스를 받을 때 듣는 플레이리스트가 있나요?', 3, '음악은 마음을 진정시키는 좋은 방법이에요.', '시끄러운 음악이나 아주 조용한 곡인가요?', '그 노래들이 마음을 어떻게 달래주나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '자기 전 머릿속으로 그리는 상상은 무엇인가요?', 3, '꿈꾸는 세상이 상상 속에 담겨 있어요.', '여행 계획이나 미래의 내 모습을 떠올려 보세요.', '그 상상이 나에게 어떤 위로를 주나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 꽃의 이름은 무엇인가요?', 3, '꽃마다 풍기는 분위기가 다 달라요.', '장미, 튤립 혹은 들꽃을 생각해보세요.', '그 꽃을 가장 좋아하게 된 추억이 있나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '사진 찍을 때 주로 담는 피사체는 무엇인가요?', 3, '기억하고 싶은 순간이 사진에 남아요.', '풍경, 음식 혹은 같이 있는 사람들인가요?', '그 장면을 기록하는 이유는 무엇인가요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 영화 장르는 무엇인가요?', 3, '영화를 통해서는 다양한 세상을 접할 수 있어요.', '로맨스, 스릴러 혹은 다큐멘터리처럼 각양각색의 영화가 있죠.', '그 중에서도 가장 좋아하는 장르가 주는 즐거움은 무엇일까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '매력을 느끼는 목소리나 말투가 있나요?', 4, '대화할 때 기분을 좋게 만드는 포인트가 있어요.', '차분한 말투나 밝은 목소리를 떠올려 보세요.', '왜 그런 느낌에 마음이 가는지 궁금해요.'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '오래된 물건 중 버리지 못하는 게 있나요?', 4, '물건에 담긴 기억은 쉽게 사라지지 않아요.', '어릴 때 인형이나 편지 혹은 일기장인가요?', '그 물건이 나에게 어떤 의미로 남아있나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '누군가에게 선물할 때 가장 고려하는 것은 무엇인가요?', 4, '나의 마음을 전달하는 나만의 기준이 있어요.', '실용성이나 디자인 혹은 상대의 취향인가요?', '선물을 고를 때 어떤 마음이 드는지 궁금해요.'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '추구하는 라이프스타일이 있나요?', 4, '와 저렿게 살고 싶다! 라고 생각되는 라이프스타일, 곰곰이 생각해보면 하나쯤은 떠오를 거에요.', '미니멀한 삶이나 북적이는 삶, 모두 멋지죠.', '그런 삶이 왜 마음에 들었나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 작가나 아티스트는 누구인가요?', 4, '취향의 정점이 누구인지 확인해보는 시간이에요.', '글귀나 그림 혹은 음악 스타일을 떠올려 보세요.', '그의 작품에서 어떤 위로를 받나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '나만의 특별한 요리 레시피가 있나요?', 4, '나를 위해 만드는 음식은 특별한 정성이에요.', '간단한 라면이나 정성 들인 찌개를 생각해보세요.', '특별 레시피를 만들게 된 이야기도 들려주세요.'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 요일은 언제인가요?', 4, '요일마다 느껴지는 공기의 무게가 달라요.', '금요일 저녁이나 일요일 아침인가요?', '왜 그 요일에 유독 마음이 가벼워지나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '전시회에 가면 작품을 보는 나만의 방식이 있나요?', 4, '예술을 즐기는 태도도 중요한 취향이에요.', '천천히 하나씩 보는지 맘에 드는 것만 보는지 생각해보세요.', '그 방식이 나의 성격과 어떻게 닮았나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '가장 좋아하는 계절의 풍경은 무엇인가요?', 4, '자연이 주는 힐링이 있어요.', '벚꽃 핀 거리나 단풍 든 산을 그려보세요.', '그 풍경을 볼 때 마음의 변화에 대해서도 떠올려봐요.'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '수집하고 싶은 물건이 있다면 무엇인가요?', 4, '모으는 건 뿌듯하고 재밌죠.', '우표, 컵, 신발 혹은 귀여운 피규어인가요?', '왜 모으게 됐는지에 대해서도 떠올려봐요.'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '10년 뒤에는 어떤 분위기의 사람이고 싶나요?', 5, '미래의 모습을 상상하면 오늘을 살 힘이 생겨요.', '내가 바라는 단단한 모습을 그려보세요.', '그 분위기를 위해 지금 무엇을 채우면 좋을까요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '나의 미적 기준은 무엇인가요?', 5, '마음에 들어서 사 모은 물건들을 보면 공통점이 있어요.', '공통점을 떠올리면 나만의 미적 기준, 취향에 대해 생각해보기 쉬울거에요.', '나만의 미적기준이 생기게 된 이유도 생각해봐요.'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '인생에서 딱 한 권의 책만 남긴다면 무엇인가요?', 5, '내 인생의 철학이 담긴 책을 고르는 일이에요.', '가장 감명 깊게 읽은 책을 생각해보세요.', '이 책이 나에게 어떤 가르침을 주었나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '나를 가장 잘 표현하는 단어 하나는 무엇인가요?', 5, '나라는 사람을 한 줄로 정의해보는 시간이에요.', '따뜻함, 성실함, 자유 같은 단어를 생각해보세요.', '왜 그 단어가 나를 가장 잘 보여주나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '어떤 공간에 있을 때 가장 나답다고 느끼나요?', 5, '공간은 나를 보호해주기도 하고 드러내기도 해요.', '도서관, 카페 혹은 침대 위 등 그 어떤 공간도 좋아요.', '그 공간이 나에게 어떤 안정감을 주나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '나의 취향이 다른 사람과 가장 다른 점은 무엇인가요?', 5, '나만의 개성을 발견하는 중요한 질문이에요.', '독특한 식성이나 음악 취향을 생각해보세요.', '이 차별점이 나를 어떻게 특별하게 만드나요?'),
((SELECT id FROM interests WHERE code = 'PREFERENCE'), '꿈꾸는 완벽한 하루는 어떤 모습인가요?', 5, '내가 행복해지는 모든 요소가 담긴 하루예요.', '아침부터 밤까지의 일정을 쭉 그려보세요.', '이 하루를 위해 오늘 할 수 있는 건 무엇인가요?'),
