((SELECT id FROM interests WHERE code = 'VALUES'), '가장 큰 용기를 냈던 순간은 언제인가요?', 2, '내 인생의 전환점이 되었던 선택이 있을 거예요.', '퇴사나 고백 혹은 낯선 곳으로의 도전인가요?', '그때 낸 용기가 지금의 나를 어떻게 만들었나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '나에게 ''약속''은 어떤 무게인가요?', 2, '다른 사람 혹은 나 자신과의 약속에 대한 생각이에요.', '무슨 일이 있어도 지키는지 혹은 유연하게 대처하는지 보세요.', '약속에 대한 평소 생각을 들려주세요.'),
((SELECT id FROM interests WHERE code = 'VALUES'), '내가 생각하는 ''공정함''이란 무엇인가요?', 2, '세상을 바라보는 나만의 정의로운 기준을 찾아보세요.', '똑같이 나누는 것인지 노력만큼 받는 것인지 보세요.', '일상에서 이 기준을 어떻게 지키며 살고 있나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '인생에서 ''운''이 차지하는 비중은 어느 정도일까요?', 2, '노력만큼이나 우연한 행운도 삶에 큰 영향을 줘요.', '내 성공이 실력인지 혹은 운이 좋았던 것인지 보세요.', '운이 좋았다고 느꼈던 특별한 경험이 있나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '나에게 ''직관''은 믿을 만한 가이드인가요?', 2, '가끔은 논리보다 느낌이 더 정확할 때가 있어요.', '첫인상을 믿는 편인지 혹은 근거를 찾는 편인지 보세요.', '직관을 믿고 결정해서 좋았던 기억이 있나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '손해를 봐도 지키고 싶은 원칙은 무엇인가요?', 3, '나를 나답게 만드는 건 스스로와의 약속이에요.', '포기하고 싶지 않은 신념을 하나 찾아보세요.', '그 원칙이 인생의 중심을 어떻게 잡아주나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '내가 생각하는 행복은 어떤 상태인가요?', 3, '행복의 기준은 나만이 정할 수 있어요.', '소소한 일상 혹은 큰 성취인지 생각해보세요.', '그 행복을 위해 지금 당장 할 수 있는 건 뭘까요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '사후 세계나 영혼의 존재를 믿으시나요?', 3, '삶 너머의 것에 대한 나의 가치관을 묻는 질문이에요.', '믿음의 여부가 지금 내 삶에 어떤 영향을 주나요?', '이 생각이 죽음을 대하는 내 태도를 어떻게 바꾸나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '내가 생각하는 ''자유''의 범위는 어디까지인가요?', 3, '구속 없는 상태가 아닌 책임 있는 선택에 대해 생각해보세요.', '내 마음대로 하는 것인지 스스로를 다스리는 것인지 보세요.', '나는 지금 충분히 자유로운 삶을 살고 있나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '세상을 바꾸는 힘은 어디에서 나온다고 생각하시나요?', 3, '변화에 대한 나의 믿음을 확인해보는 시간이에요.', '한 사람의 영웅인가요 아니면 다수의 작은 실천인가요?', '나는 그 힘에 보탬이 되는 삶을 살고 있나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '100억이 생긴다면 내 삶의 목표가 바뀔까요?', 3, '돈은 삶의 많은 부분을 바꾸지만 전부는 아닐 거예요.', '그 돈으로 사고 싶은 것보다 하고 싶은 일을 생각해보세요.', '돈이 충분해도 여전히 목표로 삼고 싶은 것이 있나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '내가 생각하는 ''삶의 균형''이란 무엇인가요?', 3, '일과 휴식,나와 타인 사이의 적당한 지점을 찾아보세요.', '어느 한쪽으로 치우치지 않으려 노력하거나 하나의 가치에 집중하고 있나요?', '지금 내 삶은 내가 원하는 균형에 가까운가요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '나에게 ''가족''이란 어떤 존재인가요?', 3, '가장 가깝고도 복잡한 관계에 대해 생각해보세요.', '안식처인가요 아니면 책임져야 할 짐인가요?', '가족에 대한 내 생각이 내 삶을 어떻게 규정하나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '인생에서 가장 큰 영향을 준 사건은 무엇인가요?', 3, '내 삶의 궤적을 바꾼 결정적인 순간이 있을 거예요.', '우연한 만남이나 예상치 못한 사고인가요?', '그 사건 이후로 내 생각은 어떻게 달라졌나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '나의 가치관과 충돌하는 상황에서 나는 어떻게 하나요?', 3, '신념을 지키는 것과 타협하는 것 사이의 갈등이에요.', '끝까지 고집하는지 혹은 유연하게 맞추는지 보세요.', '그 선택 뒤에 남는 감정은 어떤가요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '삶의 의미를 어디에서 찾으시나요?', 3, '왜 살아야 하는지에 대한 나만의 답을 찾아보세요.', '성취, 사랑 혹은 평범한 하루의 반복인가요?', '삶의 원동력이 되는 것들을 찬찬히 떠올려보세요.'),
((SELECT id FROM interests WHERE code = 'VALUES'), '돈으로 살 수 없는 것 중 가장 아끼는 건 무엇인가요?', 3, '살다 보면 돈보다 더 중요한 것들이 보여요.', '함께 쌓은 추억이나 건강 혹은 깊은 신뢰를 떠올려 보세요.', '그것들을 지키기 위해 내가 기꺼이 할 수 있는 일은 무엇인가요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '다시 태어난다면 어떤 사람으로 살고 싶나요?', 4, '지금의 내가 아닌 다른 모습을 상상해보는 시간이에요.', '지금과 완전히 다른 직업이나 성격을 그려보세요.', '왜 그런 모습으로 살아보고 싶은 걸까요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '나에게 ''일''은 어떤 의미인가요?', 4, '일은 단순히 돈을 버는 것 이상의 의미가 있어요.', '생계 수단인지 혹은 나를 표현하는 방법인지 보세요.', '일을 하면서 내가 가장 중요하게 지키고 싶은 모습은 무엇인가요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '세상에 나누고 싶은 나의 좋은 영향은 무엇인가요?', 4, '작은 친절 하나가 세상을 따뜻하게 만들어요.', '누군가에게 힘이나 위로를 줬던 일을 보세요.', '이 마음이 내 삶의 목표와 어떻게 연결될까요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '내가 가장 중요하게 생각하는 도덕적 가치는 무엇인가요?', 4, '양심의 가책을 느끼는 지점을 보면 내 도덕성이 보여요.', '정직, 책임, 배려 등이 있어요.', '이를 위해 어떤 행동을 해왔을까요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '인간의 본성은 선하다고 믿나요 악하다고 믿나요?', 4, '사람에 대한 나의 근본적인 시각을 확인해보세요.', '성선설과 성악설 중 어느 쪽에 더 마음이 가나요?', '이 믿음이 사람을 대하는 내 태도를 어떻게 만드나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '과거로 돌아갈 수 있다면 바꾸고 싶은 선택이 있나요?', 4, '후회와 아쉬움을 통해 지금의 나를 돌아보는 시간이에요.', '진로 선택이나 인연에 대한 결정이었나요?', '그 선택을 바꾼다면 지금의 나는 어떻게 변해 있을까요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '내가 생각하는 ''사회적 책임''이란 무엇인가요?', 4, '공동체 속에서 나의 역할을 정의해보는 질문이에요.', '기부나 봉사 혹은 법을 지키는 것인가요?', '나는 더 나은 사회를 위해 무엇을 할 수 있나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '나의 인생을 한 단어로 표현한다면 무엇인가요?', 4, '삶 전체를 관통하는 핵심 키워드를 찾아보세요.', '치열함, 따스함 혹은 모험인가요?', '그 단어를 선택한 이유는 무엇인가요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '억울한 일을 당했을 때 나는 어떻게 대처하나요?', 4, '나의 정의로움이 시험받는 순간은 누구에게나 힘들어요.', '끝까지 따지는 편인지 혹은 시간이 해결해주길 기다리는지 보세요.', '그 대처 방식이 내 마음을 보호하는 데 최선이었나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '고난을 겪고 있는 사람에게 해주고 싶은 말은 무엇인가요?', 4, '내가 겪은 아픔에서 얻은 지혜를 나누는 일이에요.', '진심 어린 위로인가요 아니면 현실적인 조언인가요?', '그 말이 나 자신에게도 위로가 될 수 있을까요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '내가 세상에 남기고 싶은 유산은 무엇인가요?', 4, '죽음 이후에도 남겨질 나의 흔적에 대해 생각해보세요.', '재산인가요 아니면 내가 남긴 작품이나 이름인가요?', '그 유산을 위해 지금 나는 어떻게 살고 있나요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '나에게 ''도전''은 설레는 일인가요 아니면 두려운 일인가요?', 4, '새로운 시작을 앞둔 마음가짐에서 내 성향이 보여요.', '실패에 대한 걱정이나 성공에 대한 기대 중 무엇이 더 큰지 보세요.', '두려움을 이겨내고 도전했던 마지막 기억은 언제인가요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '타인과 나를 비교하게 될 때 어떤 생각이 드나요?', 4, '남들과 비교하며 마음이 흔들리는 순간이 있기 마련이에요.', '부러움인지 혹은 자책인지 솔직한 기분을 생각해보세요.', '비교를 멈추고 나에게 집중하려면 무엇을 해야 할까요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '인생의 마지막 날, 되돌아본다면 나에게 어떤 말을 할까요?', 5, '미래에 지금의 나를 되돌아본다면 해주고 싶은 말이 분명 있을거에요.', '지나온 시간에서 가장 가치 있는 것을 골라보세요.', '그 대답 속에 담긴 내 진짜 마음은 무엇인가요?'),
((SELECT id FROM interests WHERE code = 'VALUES'), '나에게 ''죽음''은 어떤 의미로 다가오나요?', 5, '인생의 마무리를 생각하는 건 지금을 더 소중히 살게 해요.', '두려운 끝인지 혹은 자연스러운 과정의 일부인지 보세요.', '내 마지막 순간에 곁에 있었으면 하는 사람은 누구인가요?');
